arguments.keystrokes:
awk '
BEGIN {
  months["Jan"]=1; months["Feb"]=2; months["Mar"]=3; months["Apr"]=4;
  months["May"]=5; months["Jun"]=6; months["Jul"]=7; months["Aug"]=8;
  months["Sep"]=9; months["Oct"]=10; months["Nov"]=11; months["Dec"]=12;
}
{
  # Check if line contains internal API pattern
  if ($0 ~ /\/api\/v[0-9]+\/internal\//) {
    # Extract IP (first field)
    ip = $1;
    # Skip if IP starts with "10."
    if (ip ~ /^10\./) next;

    # Extract and convert timestamp
    match($0, /\[([0-9]{2})\/([A-Za-z]{3})\/([0-9]{4}):([0-9]{2}):([0-9]{2}):([0-9]{2})/, ts);
    day = ts[1];
    month = sprintf("%02d", months[ts[2]]);
    year = ts[3];
    hour = ts[4];
    min = ts[5];
    sec = ts[6];
    iso_ts = year "-" month "-" day "T" hour":" min ":" sec;

    # Replace timestamp in the line
    sub(/\[[^]]+\]/, iso_ts, $0);
    print;
  }
}' /var/log/app/access.log | head -10

